userDefinedLinkHintCss:
div > .vimiumHintMarker {
  background: #2e3440;
  border: 1px solid #4c566a;
  border-radius: 4px;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.35);
}
div > .vimiumHintMarker span {
  color: #eceff4;
  font-size: 14px;
  font-weight: 600;
}
div > .vimiumHintMarker > .matchingCharacter {
